export enum VehicleType {
  CAR = 'Carro',
  MOTORCYCLE = 'Moto',
  TRUCK = 'Caminhão'
}

export enum ServiceType {
  EMERGENCY = 'Emergência (Guincho/Socorro)',
  MAINTENANCE = 'Manutenção Geral',
  TIRE = 'Borracharia',
  ELECTRICAL = 'Elétrica'
}

export interface Coordinates {
  latitude: number;
  longitude: number;
}

export interface MapSource {
  uri: string;
  title: string;
}

export interface GroundingChunk {
  web?: {
    uri: string;
    title: string;
  };
  maps?: {
    uri: string;
    title: string;
    placeAnswerSources?: {
      reviewSnippets?: {
        snippet: string;
      }[];
    };
  };
}

export interface SearchResult {
  text: string;
  groundingChunks: GroundingChunk[];
}

import { GoogleGenAI } from "@google/genai";
import { Coordinates, SearchResult, VehicleType, ServiceType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const findMechanics = async (
  query: string,
  vehicleType: VehicleType,
  serviceType: ServiceType,
  location: Coordinates | null
): Promise<SearchResult> => {
  try {
    let prompt = `O usuário precisa de um mecânico ou serviço automotivo.
    Veículo: ${vehicleType}.
    Tipo de serviço: ${serviceType}.
    Detalhes do problema: "${query}".
    `;

    if (location) {
      prompt += ` A localização atual do usuário é Lat: ${location.latitude}, Long: ${location.longitude}. Encontre serviços próximos e relevantes.`;
    } else {
      prompt += ` O usuário não forneceu coordenadas GPS, então procure com base na localização aproximada ou cidades mencionadas na busca.`;
    }

    prompt += `
    Liste 3 a 5 opções com o nome, endereço aproximado e por que é uma boa opção.
    Se for uma rodovia, tente identificar serviços de guincho ou socorro próximos.
    IMPORTANTE: Forneça uma resposta útil e direta em formato Markdown.
    `;

    const modelId = "gemini-2.5-flash"; // Required for Maps Grounding

    const tools: any[] = [{ googleMaps: {} }];
    let toolConfig = {};

    if (location) {
      toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: location.latitude,
            longitude: location.longitude,
          },
        },
      };
    }

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: tools,
        toolConfig: toolConfig,
        // DO NOT set responseMimeType or responseSchema when using googleMaps
      },
    });

    const text = response.text || "Não foi possível encontrar informações no momento.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    return {
      text,
      groundingChunks: groundingChunks as any[], // Casting to match our interface
    };

  } catch (error) {
    console.error("Erro ao buscar mecânicos:", error);
    throw new Error("Falha ao conectar com o assistente de busca.");
  }
};

