import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { Header } from './components/Header';
import { Hero } from './components/Hero';
import { SearchForm } from './components/SearchForm';
import { ResultCard } from './components/ResultCard';
import { findMechanics } from './services/geminiService';
import { VehicleType, ServiceType, Coordinates, SearchResult } from './types';
import { MapPin, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [location, setLocation] = useState<Coordinates | null>(null);
  const [locationError, setLocationError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [searchResult, setSearchResult] = useState<SearchResult | null>(null);
  const [initialService, setInitialService] = useState<ServiceType | undefined>(undefined);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Attempt to get location on mount
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocation({
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          });
          setLocationError(null);
        },
        (err) => {
          console.error("Geolocation error:", err);
          setLocationError("Não foi possível obter sua localização exata. Os resultados podem ser menos precisos.");
        }
      );
    } else {
      setLocationError("Seu navegador não suporta geolocalização.");
    }
  }, []);

  const handleSearch = async (vehicle: VehicleType, service: ServiceType, query: string) => {
    setIsLoading(true);
    setError(null);
    setSearchResult(null);
    try {
      // If user hasn't typed a query but selected a service, provide a default query context
      const effectiveQuery = query.trim() || `Preciso de serviço de ${service}`;

      const result = await findMechanics(effectiveQuery, vehicle, service, location);
      setSearchResult(result);
    } catch (err) {
      setError("Ocorreu um erro ao buscar as informações. Tente novamente.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleEmergencyClick = () => {
    setInitialService(ServiceType.EMERGENCY);
    // Scroll to search form
    const formElement = document.querySelector('form');
    if (formElement) {
      formElement.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-20">
      <Header />
      <Hero onEmergencyClick={handleEmergencyClick} />

      <main className="flex-grow w-full max-w-5xl mx-auto px-4">

        {locationError && (
          <div className="mt-4 p-3 bg-yellow-50 text-yellow-800 text-sm rounded-lg flex items-center gap-2 border border-yellow-200 max-w-3xl mx-auto">
            <AlertCircle size={16} />
            {locationError}
          </div>
        )}

        {/* Location Status Badge */}
        {location && !locationError && (
          <div className="mt-2 flex justify-center">
            <div className="inline-flex items-center gap-1.5 bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-medium border border-green-200">
              <MapPin size={12} />
              Localização detectada
            </div>
          </div>
        )}

        <SearchForm 
          onSearch={handleSearch} 
          isLoading={isLoading} 
          initialService={initialService}
        />

        {error && (
          <div className="mt-8 p-4 bg-red-50 text-red-600 rounded-xl text-center border border-red-100">
            {error}
          </div>
        )}

        {searchResult && (
          <div className="mt-8 animate-fade-in-up">
            <h3 className="text-xl font-bold text-slate-800 mb-4 px-2">Resultados Encontrados</h3>

            {/* AI Text Response */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 mb-6 prose prose-slate max-w-none prose-a:text-orange-600 prose-headings:text-slate-800">
               <ReactMarkdown>{searchResult.text}</ReactMarkdown>
            </div>

            {/* Grounding Cards (Map Locations) */}
            {searchResult.groundingChunks && searchResult.groundingChunks.length > 0 && (
              <div className="space-y-4">
                <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider px-2">Locais no Google Maps</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {searchResult.groundingChunks.map((chunk, index) => (
                     <ResultCard key={index} chunk={chunk} />
                  ))}
                </div>
              </div>
            )}

            {searchResult.groundingChunks.length === 0 && (
              <p className="text-slate-500 text-center italic mt-4">Nenhum local específico foi retornado diretamente pelo mapa, verifique o texto acima.</p>
            )}
          </div>
        )}
      </main>

      <footer className="mt-12 py-6 text-center text-slate-400 text-sm border-t border-slate-200 bg-white">
        <p>© 2024 MecânicoJá. Resultados baseados na API do Google Maps.</p>
      </footer>
    </div>
  );
};

export default App;

