import { GoogleGenAI } from "@google/genai";
import { Coordinates, SearchResult, VehicleType, ServiceType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const findMechanics = async (
  query: string,
  vehicleType: VehicleType,
  serviceType: ServiceType,
  location: Coordinates | null,
  carModel?: string,
  problemCategory?: string
): Promise<SearchResult> => {
  try {
    let prompt = `Atue como um especialista em assistência automotiva localizando serviços.

    PERFIL DO VEÍCULO:
    - Tipo: ${vehicleType}
    - Modelo Específico: ${carModel || "Não especificado"}

    SITUAÇÃO:
    - Categoria do Serviço: ${serviceType}
    - Problema Principal: ${problemCategory || "Geral/Não classificado"}
    - Detalhes Adicionais: "${query}"
    `;

    if (location) {
      prompt += `\nLOCALIZAÇÃO: Lat: ${location.latitude}, Long: ${location.longitude}. Priorize locais a poucos quilômetros de distância.`;
    } else {
      prompt += `\nLOCALIZAÇÃO: Coordenadas não fornecidas. Use a região implícita ou sugira redes nacionais se for rodovia.`;
    }

    prompt += `
    TAREFA:
    Encontre 3 a 5 oficinas, mecânicos ou serviços de socorro que sejam ideais para este veículo e problema.

    REQUISITOS DA RESPOSTA:
    1. Se o carro for de marca específica (ex: BMW, Honda), priorize oficinas especializadas nessa marca se houver.
    2. Se for problema de pneu ou bateria, priorize borracharias ou lojas de bateria próximas.
    3. Se for rodovia, priorize guinchos e postos de serviço 24h.
    4. Forneça uma explicação curta de por que cada local foi escolhido (ex: "Especialista em Honda", "Aberto 24h", "Melhor avaliado para pneus").

    Use formatação Markdown clara.
    `;

    const modelId = "gemini-2.5-flash"; // Required for Maps Grounding

    const tools: any[] = [{ googleMaps: {} }];
    let toolConfig = {};

    if (location) {
      toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: location.latitude,
            longitude: location.longitude,
          },
        },
      };
    }

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: tools,
        toolConfig: toolConfig,
      },
    });

    const text = response.text || "Não foi possível encontrar informações no momento.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    return {
      text,
      groundingChunks: groundingChunks as any[], // Casting to match our interface
    };

  } catch (error) {
    console.error("Erro ao buscar mecânicos:", error);
    throw new Error("Falha ao conectar com o assistente de busca.");
  }
};

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { Header } from './components/Header';
import { Hero } from './components/Hero';
