import { ResultCard } from './components/ResultCard';
import { findMechanics } from './services/geminiService';
import { VehicleType, ServiceType, Coordinates, SearchResult } from './types';
import { MapPin, AlertCircle, Compass } from 'lucide-react';

const App: React.FC = () => {
  const [location, setLocation] = useState<Coordinates | null>(null);
  const [locationError, setLocationError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [searchResult, setSearchResult] = useState<SearchResult | null>(null);
  const [initialService, setInitialService] = useState<ServiceType | undefined>(undefined);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Attempt to get location on mount
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocation({
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          });
          setLocationError(null);
        },
        (err) => {
          console.error("Geolocation error:", err);
          setLocationError("Ative o GPS para encontrar serviços mais próximos de você.");
        }
      );
    } else {
      setLocationError("Seu navegador não suporta geolocalização.");
    }
  }, []);

  const handleSearch = async (
    vehicle: VehicleType, 
    service: ServiceType, 
    query: string,
    carModel: string,
    problemCategory: string
  ) => {
    setIsLoading(true);
    setError(null);
    setSearchResult(null);
    try {
      // If user hasn't typed a query but selected a category, ensure we have some text context
      let effectiveQuery = query.trim();
      if (!effectiveQuery && problemCategory) {
        effectiveQuery = `Problema reportado: ${problemCategory}`;
      } else if (!effectiveQuery && !problemCategory) {
         effectiveQuery = `Preciso de serviço de ${service}`;
      }

      const result = await findMechanics(effectiveQuery, vehicle, service, location, carModel, problemCategory);
      setSearchResult(result);
    } catch (err) {
      setError("Ocorreu um erro ao buscar as informações. Tente novamente.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleEmergencyClick = () => {
    setInitialService(ServiceType.EMERGENCY);
    // Scroll to search form
    const formElement = document.querySelector('form');
    if (formElement) {
      formElement.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <div className="min-h-screen bg-zinc-50 flex flex-col pb-20 font-sans">
      <Header />
      <Hero onEmergencyClick={handleEmergencyClick} />

      <main className="flex-grow w-full max-w-5xl mx-auto px-4 relative z-10">

        {locationError && (
          <div className="mt-6 p-4 bg-amber-50 text-amber-800 text-sm rounded-xl flex items-center gap-3 border border-amber-200 max-w-3xl mx-auto shadow-sm">
            <AlertCircle size={20} className="shrink-0" />
            <span className="font-medium">{locationError}</span>
          </div>
