        {/* Location Status Badge */}
        {location && !locationError && (
          <div className="mt-4 flex justify-center">
            <div className="inline-flex items-center gap-1.5 bg-emerald-100 text-emerald-800 px-3 py-1 rounded-full text-xs font-semibold border border-emerald-200 shadow-sm">
              <Compass size={12} />
              GPS Ativo • Localização precisa
            </div>
          </div>
        )}

        <SearchForm 
          onSearch={handleSearch} 
          isLoading={isLoading} 
          initialService={initialService}
        />

        {error && (
          <div className="mt-8 p-6 bg-rose-50 text-rose-700 rounded-2xl text-center border border-rose-100 shadow-sm">
            <p className="font-bold mb-1">Ops, algo deu errado.</p>
            <p>{error}</p>
          </div>
        )}

        {searchResult && (
          <div className="mt-12 animate-fade-in-up">
            <div className="flex items-center gap-3 mb-6 px-2">
               <div className="h-8 w-1 bg-indigo-500 rounded-full"></div>
               <h3 className="text-2xl font-bold text-zinc-800">Recomendações da IA</h3>
            </div>

            {/* AI Text Response */}
            <div className="bg-white p-8 rounded-2xl shadow-lg shadow-zinc-200/50 border border-zinc-100 mb-8 prose prose-zinc max-w-none prose-a:text-indigo-600 prose-headings:text-zinc-800 prose-strong:text-indigo-700">
               <ReactMarkdown>{searchResult.text}</ReactMarkdown>
            </div>

            {/* Grounding Cards (Map Locations) */}
            {searchResult.groundingChunks && searchResult.groundingChunks.length > 0 && (
              <div className="space-y-6">
                <div className="flex items-center justify-between px-2">
                   <h4 className="text-sm font-bold text-zinc-500 uppercase tracking-widest">Locais no Mapa</h4>
                   <span className="text-xs text-zinc-400 bg-zinc-100 px-2 py-1 rounded">Google Maps Platform</span>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {searchResult.groundingChunks.map((chunk, index) => (
                     <ResultCard key={index} chunk={chunk} />
                  ))}
                </div>
              </div>
            )}

            {searchResult.groundingChunks.length === 0 && (
              <p className="text-zinc-500 text-center italic mt-4 bg-zinc-100 p-4 rounded-lg">
