      <footer className="mt-16 py-8 text-center text-zinc-400 text-sm border-t border-zinc-200 bg-white">
        <p className="font-medium">© 2024 MecânicoJá.</p>
        <p className="mt-1 text-xs">Resultados baseados na inteligência artificial do Google Gemini e Google Maps.</p>
      </footer>
    </div>
  );
};

