          ) : (
            <>
              {user.role === 'CLIENT' ? (
                <ClientDashboard user={user} />
              ) : (
                <MechanicDashboard user={user} />
              )}
            </>
          )}
        </>
      )}

      <footer className="mt-auto py-8 text-center text-zinc-400 dark:text-zinc-600 text-sm border-t border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-900 transition-colors duration-300">
        <p className="font-medium">© 2024 FIX.</p>
        <p className="mt-1 text-xs">
          {user ? 'Conectando motoristas e mecânicos.' : 'Plataforma para Motoristas e Oficinas.'}
        </p>
      </footer>
    </div>
  );
};

