import { GoogleGenAI } from "@google/genai";
import { Coordinates, SearchResult, VehicleType, ServiceType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const findMechanics = async (
  query: string,
  vehicleType: VehicleType,
  serviceType: ServiceType,
  location: Coordinates | null,
  carModel?: string,
  problemCategory?: string
): Promise<SearchResult> => {
  try {
    const isPartsSearch = serviceType === ServiceType.PARTS;

    let prompt = "";

    if (isPartsSearch) {
      prompt = `Atue como um localizador de peças automotivas.

      PERFIL DO VEÍCULO:
      - Tipo: ${vehicleType}
      - Modelo: ${carModel || "Não especificado"}

      INTENÇÃO DO USUÁRIO:
      - Objetivo: COMPRAR PEÇAS (Varejo/Loja)
      - Item Procurado: "${query}"

      TAREFA:
      Encontre 3 a 5 LOJAS DE AUTOPEÇAS, DISTRIBUIDORAS ou REVENDEDORES autorizados próximos que provavelmente tenham este item em estoque.

      REQUISITOS DA RESPOSTA:
      1. Se o item for PNEU, priorize borracharias que vendem pneus ou lojas especializadas (ex: Michelin, Pirelli).
      2. Se for BATERIA, priorize casas de bateria.
      3. Se for peça específica (ex: farol, retrovisor), priorize desmanches credenciados ou grandes autopeças.
      4. Informe se a loja costuma ter entrega.
      `;
    } else {
      prompt = `Atue como um especialista em assistência automotiva localizando serviços mecânicos.

      PERFIL DO VEÍCULO:
      - Tipo: ${vehicleType}
      - Modelo Específico: ${carModel || "Não especificado"}

      SITUAÇÃO:
      - Categoria do Serviço: ${serviceType}
      - Problema Principal: ${problemCategory || "Geral/Não classificado"}
      - Detalhes Adicionais: "${query}"

      TAREFA:
      ${problemCategory || query.length > 5 
        ? "Encontre 3 a 5 oficinas, mecânicos ou serviços de socorro que sejam ideais para consertar este problema específico." 
        : "Liste as principais oficinas mecânicas, auto centers e prestadores de serviço bem avaliados nesta região. O usuário quer ver opções disponíveis perto dele."}
      `;
    }

    if (location) {
      prompt += `\nLOCALIZAÇÃO: Lat: ${location.latitude}, Long: ${location.longitude}. Priorize locais num raio curto.`;
    } else {
      prompt += `\nLOCALIZAÇÃO: Coordenadas não fornecidas. Use a região implícita.`;
    }

    prompt += `\nUse formatação Markdown clara. Destaque o nome do local em negrito.`;

    const modelId = "gemini-2.5-flash"; // Required for Maps Grounding

    const tools: any[] = [{ googleMaps: {} }];
    let toolConfig = {};

    if (location) {
      toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: location.latitude,
            longitude: location.longitude,
          },
        },
      };
    }

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        tools: tools,
        toolConfig: toolConfig,
      },
    });

    const text = response.text || "Não foi possível encontrar informações no momento.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    return {
      text,
      groundingChunks: groundingChunks as any[], // Casting to match our interface
    };

  } catch (error) {
    console.error("Erro ao buscar:", error);
    throw new Error("Falha ao conectar com o assistente de busca.");
  }
};

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { Hero } from './Hero';
import { SearchForm } from './SearchForm';
import { ResultCard } from './ResultCard';
import { findMechanics } from '../services/geminiService';
import { VehicleType, ServiceType, Coordinates, SearchResult, User } from '../types';
import { AlertCircle, Compass, MapPin } from 'lucide-react';

interface ClientDashboardProps {
  user: User;
  onUpgrade: () => void;
}

export const ClientDashboard: React.FC<ClientDashboardProps> = ({ user, onUpgrade }) => {
  const [location, setLocation] = useState<Coordinates | null>(null);
  const [locationError, setLocationError] = useState<string | null>(null);

  // State for manual search
  const [isLoading, setIsLoading] = useState(false);
  const [searchResult, setSearchResult] = useState<SearchResult | null>(null);
  const [initialService, setInitialService] = useState<ServiceType | undefined>(undefined);
  const [error, setError] = useState<string | null>(null);

  // State for nearby mechanics (auto-load)
  const [nearbyMechanics, setNearbyMechanics] = useState<SearchResult | null>(null);
  const [loadingNearby, setLoadingNearby] = useState(false);

  useEffect(() => {
    // Attempt to get location on mount
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const coords = {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          };
          setLocation(coords);
          setLocationError(null);
        },
        (err) => {
          console.error("Geolocation error object:", err);
          let msg = "Erro desconhecido ao obter localização.";

          if (err.code === 1) msg = "Permissão de localização negada. Ative o GPS para ver mecânicos próximos.";
          else if (err.code === 2) msg = "Sinal de GPS indisponível ou fraco.";
          else if (err.code === 3) msg = "O tempo para obter a localização esgotou.";
          else if (err.message) msg = err.message;

          setLocationError(msg);
        },
        { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
      );
    } else {
      setLocationError("Seu navegador não suporta geolocalização.");
    }
  }, []);

  // Fetch nearby mechanics automatically once location is found
  useEffect(() => {
    if (location && !nearbyMechanics && !loadingNearby) {
      setLoadingNearby(true);
      findMechanics(
        "Listar todas as oficinas mecânicas disponíveis na região",
        VehicleType.CAR,
        ServiceType.MAINTENANCE,
        location
      )
      .then((result) => {
        setNearbyMechanics(result);
      })
      .catch((e) => console.error("Auto fetch failed", e))
      .finally(() => setLoadingNearby(false));
    }
  }, [location]);

  const handleSearch = async (
    vehicle: VehicleType, 
    service: ServiceType, 
    query: string,
    carModel: string,
    problemCategory: string
  ) => {
    setIsLoading(true);
    setError(null);
    setSearchResult(null);
    try {
      let effectiveQuery = query.trim();
      if (!effectiveQuery && problemCategory) {
        effectiveQuery = `Problema reportado: ${problemCategory}`;
      } else if (!effectiveQuery && !problemCategory) {
         effectiveQuery = `Preciso de serviço de ${service}`;
      }

      const result = await findMechanics(effectiveQuery, vehicle, service, location, carModel, problemCategory);
      setSearchResult(result);
    } catch (err) {
      setError("Ocorreu um erro ao buscar as informações. Tente novamente.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleEmergencyClick = () => {
    setInitialService(ServiceType.EMERGENCY);
    const formElement = document.querySelector('form');
    if (formElement) {
      formElement.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <>
      <Hero onEmergencyClick={handleEmergencyClick} onPrimeClick={onUpgrade} />

      <main className="w-full max-w-5xl mx-auto px-4 relative z-10 pb-20">

        {locationError && (
          <div className="mt-6 p-4 bg-amber-50 dark:bg-amber-900/30 text-amber-800 dark:text-amber-200 text-sm rounded-xl flex items-center gap-3 border border-amber-200 dark:border-amber-800 max-w-3xl mx-auto shadow-sm">
            <AlertCircle size={20} className="shrink-0" />
            <span className="font-medium">{locationError}</span>
          </div>
        )}

        {location && !locationError && (
          <div className="mt-4 flex justify-center">
            <div className="inline-flex items-center gap-1.5 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-800 dark:text-emerald-300 px-3 py-1 rounded-full text-xs font-semibold border border-emerald-200 dark:border-emerald-800 shadow-sm">
              <Compass size={12} />
              GPS Ativo • Localização precisa
            </div>
          </div>
        )}

        <SearchForm 
          onSearch={handleSearch} 
          isLoading={isLoading} 
          initialService={initialService}
        />

        {error && (
          <div className="mt-8 p-6 bg-rose-50 dark:bg-rose-900/20 text-rose-700 dark:text-rose-300 rounded-2xl text-center border border-rose-100 dark:border-rose-800 shadow-sm">
            <p className="font-bold mb-1">Ops, algo deu errado.</p>
            <p>{error}</p>
          </div>
        )}

        {/* RESULTS SECTION: Shows either Manual Search OR Nearby Mechanics (Default) */}

        {(searchResult || nearbyMechanics) && (
          <div className="mt-12 animate-fade-in-up">

            {/* Header Title Switch */}
            <div className="flex items-center gap-3 mb-6 px-2">
               <div className={`h-8 w-1 rounded-full ${searchResult ? 'bg-indigo-500' : 'bg-emerald-500'}`}></div>
               <h3 className="text-2xl font-bold text-zinc-800 dark:text-zinc-100">
                 {searchResult ? 'Recomendações da IA' : 'Oficinas em Destaque na Sua Região'}
               </h3>
               {!searchResult && loadingNearby && (
                 <span className="text-sm text-zinc-400 animate-pulse">Carregando locais...</span>
               )}
            </div>

            {/* Display Text Content (Tips) */}
            <div className="bg-white dark:bg-zinc-800 p-8 rounded-2xl shadow-lg shadow-zinc-200/50 dark:shadow-none border border-zinc-100 dark:border-zinc-700 mb-8 prose prose-zinc dark:prose-invert max-w-none prose-a:text-indigo-600 dark:prose-a:text-indigo-400 prose-headings:text-zinc-800 dark:prose-headings:text-zinc-100 prose-strong:text-indigo-700 dark:prose-strong:text-indigo-400">
               <ReactMarkdown>
                 {(searchResult || nearbyMechanics)?.text || ''}
               </ReactMarkdown>
            </div>

            {/* Display Cards */}
            {((searchResult || nearbyMechanics)?.groundingChunks?.length ?? 0) > 0 && (
              <div className="space-y-6">
                <div className="flex items-center justify-between px-2">
                   <h4 className="text-sm font-bold text-zinc-500 dark:text-zinc-400 uppercase tracking-widest">
                     {searchResult ? 'Locais Encontrados' : 'Perto de Você'}
                   </h4>
                   <span className="text-xs text-zinc-400 dark:text-zinc-500 bg-zinc-100 dark:bg-zinc-800 px-2 py-1 rounded">Google Maps Platform</span>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {(searchResult || nearbyMechanics)?.groundingChunks.map((chunk, index) => (
                     <ResultCard key={index} chunk={chunk} />
                  ))}
                </div>
              </div>
            )}

            {/* Empty State */}
            {((searchResult || nearbyMechanics)?.groundingChunks?.length ?? 0) === 0 && !loadingNearby && (
              <p className="text-zinc-500 dark:text-zinc-400 text-center italic mt-4 bg-zinc-100 dark:bg-zinc-800 p-4 rounded-lg">
                Nenhum local específico foi retornado pelo mapa, mas verifique as sugestões no texto acima.
              </p>
            )}
          </div>
        )}
      </main>
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AuthScreen } from './components/AuthScreen';
import { ClientDashboard } from './components/ClientDashboard';
import { MechanicDashboard } from './components/MechanicDashboard';
import { UserProfile } from './components/UserProfile';
import { SubscriptionScreen } from './components/SubscriptionScreen';
import { SplashScreen } from './components/SplashScreen';
import { User } from './types';

type ViewState = 'dashboard' | 'profile' | 'subscription';

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [showConfetti, setShowConfetti] = useState(false);

  // Theme State
  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      const savedTheme = localStorage.getItem('theme');
      if (savedTheme) {
        return savedTheme === 'dark';
      }
      return window.matchMedia('(prefers-color-scheme: dark)').matches;
    }
    return false;
  });

  // Listen for system theme changes
  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const handleChange = (e: MediaQueryListEvent) => {
      // Only update automatically if user hasn't set a preference manually (no localStorage key)
      if (!localStorage.getItem('theme')) {
        setIsDarkMode(e.matches);
      }
    };

    mediaQuery.addEventListener('change', handleChange);
    return () => mediaQuery.removeEventListener('change', handleChange);
  }, []);

  // Apply theme class to html element without persisting automatically
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleTheme = () => {
    setIsDarkMode(prev => {
      const newValue = !prev;
      // When toggled manually, save preference
      localStorage.setItem('theme', newValue ? 'dark' : 'light');
      return newValue;
    });
  };

  const handleLogin = (newUser: User) => {
    // Garantir que o user tenha o campo plan se vier do mock antigo
    const userWithPlan = { ...newUser, plan: newUser.plan || 'FREE' };
    setUser(userWithPlan);
    setCurrentView('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentView('dashboard');
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUser(updatedUser);
  };

  const handleSubscribe = () => {
    if (user) {
      const newPlan = user.role === 'MECHANIC' ? 'PRO' : 'PRIME';
      setUser({ ...user, plan: newPlan });
      setCurrentView('dashboard');
      // Trigger success animation visually
      const button = document.getElementById('plan-badge');
      if (button) button.classList.add('animate-bounce');
    }
  };

  if (loading) {
    return <SplashScreen onFinish={() => setLoading(false)} />;
  }

  return (
    <div className="min-h-screen bg-zinc-50 dark:bg-zinc-950 flex flex-col font-sans transition-colors duration-300">
      <Header 
        user={user} 
        onLogout={handleLogout} 
        onProfileClick={() => setCurrentView('profile')}
        onPlanClick={() => setCurrentView('subscription')}
        isDarkMode={isDarkMode}
        toggleTheme={toggleTheme}
      />

      <main className="flex-grow">
        {!user ? (
          <div className="animate-page-enter">
            <AuthScreen onLogin={handleLogin} />
          </div>
        ) : (
          <div key={currentView} className="animate-page-enter">
            {currentView === 'profile' ? (
              <UserProfile 
                user={user} 
                onSave={handleUpdateUser} 
                onBack={() => setCurrentView('dashboard')} 
              />
            ) : currentView === 'subscription' ? (
              <SubscriptionScreen 
                user={user}
                onSubscribe={handleSubscribe}
                onBack={() => setCurrentView('dashboard')}
              />
            ) : (
              <>
                {user.role === 'CLIENT' ? (
                  <ClientDashboard user={user} onUpgrade={() => setCurrentView('subscription')} />
                ) : (
                  <MechanicDashboard user={user} onUpgrade={() => setCurrentView('subscription')} />
                )}
              </>
            )}
          </div>
        )}
      </main>

      {/* Footer com ajuste para Safe Area do iPhone (pb-safe ou padding-bottom via env) */}
      <footer className="mt-auto py-8 text-center text-zinc-400 dark:text-zinc-600 text-sm border-t border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-900 transition-colors duration-300 pb-[env(safe-area-inset-bottom)]">
        <div className="pb-4">
          <p className="font-medium">© 2024 FIX.</p>
          <p className="mt-1 text-xs">
            {user ? 'Conectando motoristas e mecânicos.' : 'Plataforma para Motoristas e Oficinas.'}
          </p>
        </div>
      </footer>
    </div>
  );
};

